const stepData = items[0].json;
const currentStep = stepData.step_number;
const masterImage = stepData.master_ref;

// --- 1. เลือกรูป Input ---
let inputImage = masterImage; 
if (currentStep < 6) {
  try {
     const lastResult = $("Gen Step Image").last();
     const lastImgUrl = lastResult.json.data.resultJson.resultUrls[0];
     if (lastImgUrl) inputImage = lastImgUrl;
  } catch (error) {
     inputImage = masterImage; 
  }
}

// --- 2. Prompt & Strength (สูตร Pro Camouflage) ---
let prompt = "";
let strength = 0.65; 

if (currentStep === 6) {
   // Step 6: เริ่มเก่า (Strength เบาๆ รักษาโครง)
   prompt = "Interior design, same room structure, slightly dusty floor, dim lighting, realistic texture.";
   strength = 0.40; 
} 
else if (currentStep === 5) {
   // Step 5: เปลี่ยนเฟอร์นิเจอร์เป็นกองของคลุมผ้า
   prompt = "Construction site, renovation in progress, furniture covered with white plastic sheets, piles of cardboard boxes, unfinished room.";
   strength = 0.65; 
}
else if (currentStep === 4) {
   // Step 4: เปลี่ยนกองผ้า เป็นกองวัสดุก่อสร้าง
   prompt = "Hard construction zone, piles of wood and drywalls on floor, raw concrete flooring, removed ceiling, construction tools.";
   strength = 0.70;
}
else if (currentStep === 3) {
   // Step 3: งานระบบดิบๆ
   prompt = "Unfinished interior, raw concrete walls, exposed electrical wiring, PVC pipes, heavy dust, construction debris.";
   strength = 0.70;
}
else if (currentStep === 2) {
   // Step 2: ทุบห้อง
   prompt = "Demolished room, smashed walls, rubble and bricks on floor, broken windows, dirty, heavy renovation site.";
   strength = 0.75;
}
else if (currentStep === 1) {
   // Step 1: ร้าง
   prompt = "Abandoned ruins, decayed building, peeling paint, thick cobwebs, dark atmosphere, haunted, very dirty.";
   strength = 0.80;
}

return {
  json: {
    step: currentStep,
    prompt_text: prompt,
    strength_val: strength,
    image_input: inputImage,
    job_id: stepData.job_id
  }
};

const data = items[0].json;

// ดึงค่าตัวแปร (เขียนเผื่อไว้ให้ทั้ง 2 กรณี เผื่อชื่อตัวแปรเปลี่ยน)
const masterImage = data.final_image || data.image_scene_7; 
const masterPrompt = data.clean_prompt || data.prompt_scene_7;
const jobId = data.job_id;

const tasks = [];

// --- สร้างรายการงาน 6 ชิ้น (ถอยหลัง: Step 6 -> 1) ---
for (let i = 6; i >= 1; i--) {
  tasks.push({
    json: {
      step_number: i,           // เลข Step ปัจจุบัน (6,5,4...)
      job_id: jobId,            // เลข Job ID เดิม
      master_ref: masterImage,  // รูปต้นฉบับ (รูปที่ 7 ที่สวยแล้ว)
      master_prompt: masterPrompt // Prompt ต้นฉบับ
    }
  });
}

return tasks;

