const rawData = items[0].json.data;

// ตั้งค่าเริ่มต้น (Default)
let cleanPrompt = "N/A"; 
let cleanSize = "4:3";
let finalImage = "";

// --- 1. Image (resultJson) ---
try {
  if (typeof rawData.resultJson === 'string') {
    finalImage = JSON.parse(rawData.resultJson).resultUrls[0];
  } else if (rawData.resultJson && rawData.resultJson.resultUrls) {
    finalImage = rawData.resultJson.resultUrls[0];
  }
} catch (e) {
  finalImage = "Error: Image Not Found";
}

// --- 2. Prompt (param) ---
try {
  let params = rawData.param;

  // ชั้นที่ 1: param
  if (typeof params === 'string') {
    params = JSON.parse(params);
  }

  //  ชั้นที่ 2 (จุดที่แก้เพิ่ม): เช็คว่า input เป็น text หรือไม่?
  if (params.input && typeof params.input === 'string') {
    params.input = JSON.parse(params.input);
  }

  if (params.input) {
    if (params.input.prompt) cleanPrompt = params.input.prompt;
    if (params.input.image_size) cleanSize = params.input.image_size;
  }

} catch (e) {
  cleanPrompt = "Error: Prompt logic failed (" + e.message + ")";
}

// --- 3. ส่งข้อมูลออกไป ---
return {
  json: {
    job_id: $('Telegram Trigger1').first().json.message.message_id,
    final_image: finalImage,
    clean_prompt: cleanPrompt,
    dimension: cleanSize
  }
};

