let sourceNode;
try {
    sourceNode = $('Update Image in sheet').first().json;
} catch (e) {
    // กรณี Test แล้วหาไม่เจอจริงๆ ให้ Default เป็น 6 ไว้ก่อน เพื่อให้ Code ไม่แดง
    sourceNode = { "image_scene_6": "test_url" }; 
}

// หาว่า key ไหนคือ image_scene_X
const keys = Object.keys(sourceNode);
const sceneKey = keys.find(k => k.startsWith('image_scene_')); 
// ผลลัพธ์จะได้ string เช่น "image_scene_6"

// ตัดเอาตัวเลขออกมา (แยกด้วย _)
// image (0) _ scene (1) _ 6 (2) -> เอาตัวที่ index 2
let currentScene = 6; // ค่า Default
if (sceneKey) {
    currentScene = parseInt(sceneKey.split('_')[2]);
}

const nextScene = currentScene + 1;

// 4. เตรียมข้อมูล
const rowData = $json; 
let partnerUrl = "";

// 5. Logic เลือกคู่ 
if (currentScene === 6) {
    // คู่กับรูป Original (Scene 7)
    if (rowData["image_scene_7"]) {
        partnerUrl = rowData["image_scene_7"];
    } else {
        // กันเหนียว: ดึงจาก Node แรกสุด
        try { partnerUrl = $('Get a file1').first().json.url; } catch(e) {}
    }
} else {
    // คู่กับรูป Scene ก่อนหน้า
    partnerUrl = rowData["image_scene_" + nextScene];
}

return {
    json: {
        job_id: rowData.job_id,
        current_scene: currentScene, // ต้องได้เลข 6
        partner_scene: nextScene,    // ต้องได้เลข 7
        start_image: rowData["image_scene_" + currentScene],
        end_image: partnerUrl,
        target_column: `video_clip_${currentScene}` // ต้องได้ video_clip_6
    }
}

// Mock Video Generator
return {
    json: {
        id: "mock_job_123",
        state: "completed",
        assets: {
            video: "https://www.w3schools.com/html/mov_bbb.mp4" // คลิปตัวอย่างฟรี
        }
    }
}

const partnerData = $('Find My Partner').first().json;

// --- จุดที่แก้: นักสืบหา URL (รองรับทุกท่าของ Fal/Seedance) ---
let videoUrl = "";

// ฟังก์ชันช่วยเจาะดูไส้ใน JSON (Safe Navigation)
const get = (obj, path) => path.split('.').reduce((acc, part) => acc && acc[part], obj);

// ไล่เช็คทุกซอกทุกมุม
if (get($json, 'video.url')) {
    videoUrl = $json.video.url;             // แบบมาตรฐาน Fal
} else if (get($json, 'output.video.url')) {
    videoUrl = $json.output.video.url;      // แบบ Seedance
} else if (get($json, 'output.url')) {
    videoUrl = $json.output.url;            // แบบบางโมเดล
} else if (get($json, 'assets.video')) {
    videoUrl = $json.assets.video;          // แบบ Luma 
} else {
    // ถ้าหาไม่เจอจริงๆ ให้ฟ้อง Error พร้อม Status จะได้รู้ว่าเกิดอะไรขึ้น
    videoUrl = "Error: Video URL not found (Status: " + ($json.status || "Unknown") + ")";

    // Debug: ลองปริ้นท์ JSON ออกมาดู (ดูใน Console Log ถ้าจำเป็น)
    // console.log($json);
}

// สร้าง JSON ที่มี key เป็นชื่อคอลัมน์จริงๆ
const dynamicColumnName = partnerData.target_column;

return {
    json: {
        job_id: partnerData.job_id,
        [dynamicColumnName]: videoUrl 
    }
}

const step = $('Chain Logic').item.json.step;
const jobId = $('Chain Logic').item.json.job_id;
const promptText = $('Chain Logic').item.json.prompt_text;

// ดึงลิ้งค์รูปจาก ImgBB (Node ก่อนหน้า)
const imageUrl = items[0].json.data.url;

// สร้าง Object ใหม่ ที่มีแค่ข้อมูลที่เราจะอัปเดตจริงๆ
const dataToUpdate = {
  "job_id": jobId
};

// ใส่ข้อมูลลงไปเฉพาะ Step นี้ (เช่น image_scene_6)
dataToUpdate[`image_scene_${step}`] = imageUrl;
dataToUpdate[`prompt_scene_${step}`] = promptText;

return { json: dataToUpdate };

// ดึงข้อมูลแถว
const row = $json; 

// รวบรวมคลิปเรียงตามลำดับ (1 -> 6)
const clips = [];
for (let i = 1; i <= 6; i++) {
  const url = row[`video_clip_${i}`];
  if (url) {
    clips.push(url);
  }
}

// สร้าง Elements สำหรับ Creatomate พร้อม Transition
// เราจะใช้ track 1 เหมือนกันหมด เพื่อให้มันวางต่อกัน
// แต่ใส่ "transition" ให้คลิปถัดไปซ้อนทับคลิปก่อนหน้า
const elements = clips.map((url, index) => {
  // คลิปแรกไม่ต้องมี transition
  if (index === 0) {
    return {
      "type": "video",
      "source": url,
      "track": 1 
    };
  } 

  // คลิปที่ 2 เป็นต้นไปใส่ Transition
  return {
    "type": "video",
    "source": url,
    "track": 1,
    // transition: null,
    "transition": {
      "type": "mix",    // สั่งละลายภาพ (Cross Dissolve)
      "duration": "1s"  // ระยะเวลาซ้อนทับ 1 วินาที (ปรับลดได้ถ้าคลิปสั้น)
    }
  };
});

return {
  json: {
    ...row, //เพื่อรักษารูปภาพและข้อมูลอื่นๆ ไว้
    creatomate_elements: elements
  }
}

